def loan_type_label(loan_type_id: Optional[str]) -> str:
    if not loan_type_id:
        return ""
    for choice in LOAN_TYPE_CHOICES:
        if choice["id"] == loan_type_id:
            return choice["label"]
    # Replace underscores and hyphens with spaces
    label = loan_type_id.replace("_", " ").replace("-", " ")
    # Insert space between CamelCase words (e.g. HardMoney -> Hard Money)
    label = re.sub(r'(?<=[a-z])(?=[A-Z])', ' ', label)
    label = re.sub(r'(?<=[A-Z])(?=[A-Z][a-z])', ' ', label)
    # Case-insensitive replacement of "hardmoney" with "hard money"
    label = re.sub(r'(?i)hardmoney', lambda m: 'Hard Money' if m.group(0).istitle() or m.group(0)[0].isupper() else 'hard money', label)
    # Clean up multiple spaces
    label = re.sub(r'\s+', ' ', label).strip()
    return label.title()

